mapper.select:
SELECT mgm.cug_id ,mgm.cug_nm ,dcm.cug_expl ,mgm.use_yn ,mgm.prp_sttl_abl_yn ,TO_CHAR(dcm.stm_fir_reg_date,'YYYY.MM.DD HH24:MI') stm_fir_reg_date ,reg.user_nm as regNm ,TO_CHAR(dcm.stm_last_upd_date,'YYYY.MM.DD HH24:MI') stm_last_upd_date ,upd.user_nm as updNm FROM mn_cug_mst mgm ,dm_cug_mst dcm ,ad_user_mst reg ,ad_user_mst upd WHERE 1=1 AND mgm.cug_id = dcm.cug_id AND reg.user_id(+) = dcm.stm_fir_reg_user_id AND upd.user_id(+) = dcm.stm_last_upd_user_id
AND mgm.cug_id = #{textCugId}
AND UPPER(mgm.cug_nm) LIKE '%' || UPPER(#{textCugNm}) || '%'
AND mgm.prp_sttl_abl_yn = #{selectPrpSttlAblYn}
AND mgm.use_yn = #{selectUseYn}
AND mgm.use_yn = 'Y' ORDER BY mgm.cug_nm ASC

mapper.update:

UPDATE dm_cug_mst
    SET cug_expl = #{cugExpl}
        , stm_last_upd_user_id  = #{stmLastUpdUserId}
        , stm_last_upd_date = SYSDATE
WHERE cug_id = #{cugId}

