SELECT a.modl_cd ,e.model_name as modlNm ,a.use_yn ,a.modl_fg_cd ,(select cd_nm from ad_comm_cd where comm_cd = a.modl_fg_cd and comm_grp_cd = 'MODL_FG_CD') modl_fg_nm ,a.modl_os_fg_cd ,(select cd_nm from ad_comm_cd where comm_cd = a.modl_os_fg_cd and comm_grp_cd = 'MODL_OS_FG_CD') modl_os_fg_nm ,a.modl_manufr_fg_cd ,(select cd_nm from ad_comm_cd where comm_cd = a.modl_manufr_fg_cd and comm_grp_cd = 'MODL_MANUFR_FG_CD') modl_manufr_fg_nm ,TO_CHAR(a.stm_last_upd_date,'YYYY.MM.DD HH24:MI') stm_last_upd_date ,(SELECT user_nm FROM ad_user_mst WHERE user_id = a.stm_last_upd_user_id) stm_last_upd_user_nm FROM dm_dvc_modl_mst a ,stb_model e WHERE 1=1 AND a.modl_cd = e.model_code AND substr(a.modl_cd,0,2) not in ('11','12')
AND e.model_name LIKE '%' || #{txtModelNm} || '%'
AND a.modl_fg_cd IN
#{value}
AND a.modl_os_fg_cd IN
#{value}
AND a.modl_manufr_fg_cd IN
#{value}
AND a.use_yn = 'Y' ORDER BY e.model_name
